/**
 * escher-fba.min.js
 * =================
 * Implements the escherFba interface expected by escher-FBA_code3_2.js:
 *
 *   escherFba.loadModel(xmlString)         → model object
 *   model.setUpperBound(reactionId, value) → void
 *   escherFba.solve(model, solver)         → { objectiveValue, fluxes }
 *
 * Uses glpk.js (already loaded as window.glpk / the glpk() async factory)
 * for LP solving. Parses SBML Level 2/3 with FBC package annotations.
 *
 * SBML parsing covers:
 *   - listOfReactions / listOfSpecies / listOfCompartments
 *   - stoichiometry from listOfReactants / listOfProducts
 *   - flux bounds from fbc:fluxBound or reaction attributes (lower/upperFluxBound)
 *   - objective function from fbc:listOfObjectives or fallback to BIOMASS reaction
 */

const escherFba = (function () {

    // ── SBML parser ───────────────────────────────────────────────────────────

    function parseModel(xmlString) {
        const parser = new DOMParser();
        const doc    = parser.parseFromString(xmlString, 'application/xml');

        const parseError = doc.querySelector('parsererror');
        if (parseError) throw new Error('SBML parse error: ' + parseError.textContent.slice(0, 200));

        // ── Species (metabolites) ─────────────────────────────────────────────
        const speciesMap = {};
        doc.querySelectorAll('listOfSpecies > species').forEach(s => {
            speciesMap[s.getAttribute('id')] = {
                id:          s.getAttribute('id'),
                name:        s.getAttribute('name') || s.getAttribute('id'),
                compartment: s.getAttribute('compartment'),
            };
        });

        // ── Flux bounds lookup (fbc:listOfFluxBounds) ─────────────────────────
        const fbcBounds = {};
        doc.querySelectorAll('listOfFluxBounds > fluxBound, fluxBound').forEach(fb => {
            const rxn = fb.getAttribute('reaction');
            const op  = fb.getAttribute('operation') || 'lessEqual';
            const val = parseFloat(fb.getAttribute('value'));
            if (!fbcBounds[rxn]) fbcBounds[rxn] = {};
            if (op === 'greaterEqual' || op === 'greaterThanOrEqual') fbcBounds[rxn].lb = val;
            if (op === 'lessEqual'    || op === 'lessThanOrEqual')    fbcBounds[rxn].ub = val;
            if (op === 'equal')       { fbcBounds[rxn].lb = val; fbcBounds[rxn].ub = val; }
        });

        // ── Reactions ─────────────────────────────────────────────────────────
        const reactions = [];
        const reactionIndex = {};

        doc.querySelectorAll('listOfReactions > reaction').forEach(r => {
            const id  = r.getAttribute('id');
            const rev = r.getAttribute('reversible') !== 'false';

            // Stoichiometry
            const stoich = {};
            r.querySelectorAll('listOfReactants > speciesReference').forEach(sr => {
                const sp  = sr.getAttribute('species');
                const st  = parseFloat(sr.getAttribute('stoichiometry') || '1');
                stoich[sp] = (stoich[sp] || 0) - st;   // reactants are negative
            });
            r.querySelectorAll('listOfProducts > speciesReference').forEach(sr => {
                const sp  = sr.getAttribute('species');
                const st  = parseFloat(sr.getAttribute('stoichiometry') || '1');
                stoich[sp] = (stoich[sp] || 0) + st;   // products are positive
            });

            // Bounds — priority: fbc:fluxBound > reaction attributes > defaults
            let lb = fbcBounds[id]?.lb;
            let ub = fbcBounds[id]?.ub;

            if (lb === undefined) {
                const lbAttr = r.getAttribute('lowerFluxBound') || r.getAttribute('fbc:lowerFluxBound');
                lb = lbAttr ? parseFloat(lbAttr) : (rev ? -1000 : 0);
            }
            if (ub === undefined) {
                const ubAttr = r.getAttribute('upperFluxBound') || r.getAttribute('fbc:upperFluxBound');
                ub = ubAttr ? parseFloat(ubAttr) : 1000;
            }

            const rxn = { id, stoich, lb, ub, _origUb: ub };
            reactions.push(rxn);
            reactionIndex[id] = rxn;
        });

        // ── Objective function ────────────────────────────────────────────────
        // Try fbc:listOfObjectives first
        let objectiveReactions = {};
        const objList = doc.querySelector('listOfObjectives objective, objective[type="maximize"], objective');
        if (objList) {
            objList.querySelectorAll('fluxObjective, listOfFluxObjectives > fluxObjective').forEach(fo => {
                const rxn  = fo.getAttribute('reaction');
                const coef = parseFloat(fo.getAttribute('coefficient') || '1');
                objectiveReactions[rxn] = coef;
            });
        }

        // Fallback: find a reaction with "biomass" in the id (case-insensitive)
        if (Object.keys(objectiveReactions).length === 0) {
            const biomassRxn = reactions.find(r =>
                /biomass/i.test(r.id) || /growth/i.test(r.id)
            );
            if (biomassRxn) {
                objectiveReactions[biomassRxn.id] = 1;
                console.log('[escherFba] Objective fallback: using', biomassRxn.id);
            } else {
                // Last resort: use the last reaction
                const last = reactions[reactions.length - 1];
                if (last) objectiveReactions[last.id] = 1;
                console.warn('[escherFba] Could not find biomass reaction — using last reaction as objective');
            }
        }

        console.log('[escherFba] Model loaded —',
            reactions.length, 'reactions,',
            Object.keys(speciesMap).length, 'species');
        console.log('[escherFba] Objective:', Object.keys(objectiveReactions));

        return {
            reactions,
            reactionIndex,
            speciesMap,
            objectiveReactions,

            setUpperBound(reactionId, value) {
                const rxn = this.reactionIndex[reactionId];
                if (rxn) {
                    rxn.ub = value;
                } else {
                    // Silent — exchange reactions may not all be present in every model
                    console.debug('[escherFba] setUpperBound: reaction not found —', reactionId);
                }
            },

            setLowerBound(reactionId, value) {
                const rxn = this.reactionIndex[reactionId];
                if (rxn) rxn.lb = value;
            },

            reset() {
                // Restore all bounds to original parsed values
                this.reactions.forEach(r => { r.ub = r._origUb; });
            },
        };
    }

    // ── FBA solver ────────────────────────────────────────────────────────────

    /**
     * Build a glpk.js LP problem from the model and solve it.
     *
     * glpk.js API:
     *   solver.GLP_MAX / GLP_MIN
     *   solver.GLP_CV  (continuous variable)
     *   solver.GLP_FX, GLP_LO, GLP_UP, GLP_DB (bound types)
     *   solver.solve(lp, opts) → { result: { z, vars } }
     */
    function solve(model, solver) {
        const { reactions, speciesMap, objectiveReactions } = model;

        // Build species → constraint index map
        const speciesIds = Object.keys(speciesMap);
        const speciesIdx = {};
        speciesIds.forEach((id, i) => { speciesIdx[id] = i + 1; });  // 1-indexed for glpk

        // ── Objective coefficients ─────────────────────────────────────────────
        const obj = { direction: solver.GLP_MAX, name: 'biomass', vars: [] };
        reactions.forEach((r, j) => {
            const coef = objectiveReactions[r.id] || 0;
            if (coef !== 0) obj.vars.push({ name: r.id, coef });
        });

        // ── Constraints (stoichiometric mass balance: S·v = 0) ────────────────
        const subjectTo = [];
        speciesIds.forEach((spId, i) => {
            const vars = [];
            reactions.forEach(r => {
                const s = r.stoich[spId];
                if (s && s !== 0) vars.push({ name: r.id, coef: s });
            });
            if (vars.length > 0) {
                subjectTo.push({
                    name:  'mb_' + spId,
                    vars,
                    bnds:  { type: solver.GLP_FX, ub: 0, lb: 0 },  // steady-state
                });
            }
        });

        // ── Variable bounds ────────────────────────────────────────────────────
        const bounds = reactions.map(r => {
            let type;
            if (r.lb === r.ub)                             type = solver.GLP_FX;
            else if (isFinite(r.lb) && isFinite(r.ub))    type = solver.GLP_DB;
            else if (isFinite(r.lb))                       type = solver.GLP_LO;
            else if (isFinite(r.ub))                       type = solver.GLP_UP;
            else                                           type = solver.GLP_FR;

            return { name: r.id, type, lb: r.lb, ub: r.ub };
        });

        const lp = { name: 'GEMgen_FBA', objective: obj, subjectTo, bounds };

        // ── Solve ──────────────────────────────────────────────────────────────
        let result;
        try {
            result = solver.solve(lp, { msglev: solver.GLP_MSG_OFF });
        } catch (e) {
            console.error('[escherFba] glpk solve error:', e);
            return { objectiveValue: 0, fluxes: {}, status: 'error' };
        }

        if (!result || result.result === undefined) {
            console.warn('[escherFba] glpk returned no result');
            return { objectiveValue: 0, fluxes: {}, status: 'infeasible' };
        }

        const z      = result.result.z     || 0;
        const vars   = result.result.vars  || {};
        const status = result.result.status;

        // glpk status codes: 5 = GLP_OPT (optimal)
        if (status !== solver.GLP_OPT && status !== 5) {
            console.warn('[escherFba] Non-optimal solution status:', status);
        }

        console.log('[escherFba] FBA solved — objective:', z.toFixed(6), '| status:', status);

        return {
            objectiveValue: z,
            fluxes:         vars,
            status:         status === 5 ? 'optimal' : 'non-optimal',
        };
    }

    // ── Public API ────────────────────────────────────────────────────────────
    return {
        loadModel: parseModel,
        solve,
    };

})();
